@page "/courses"
@rendermode InteractiveServer
@inject ICatalogService CatalogService

<PageTitle>Course Catalog - University Course Catalog</PageTitle>

<div class="container">
    <h1 class="mb-4">Course Catalog</h1>

    <div class="row mb-4">
        <div class="col-md-6">
            <input type="text" class="form-control" placeholder="Search by title, code, or instructor..."
                   @bind="searchTerm" @bind:event="oninput" />
        </div>
        <div class="col-md-4">
            <select class="form-select" @bind="selectedDepartmentId">
                <option value="0">All Departments</option>
                @foreach (var dept in departments)
                {
                    <option value="@dept.Id">@dept.Name</option>
                }
            </select>
        </div>
    </div>

    @if (filteredCourses.Any())
    {
        <div class="table-responsive">
            <table class="table table-striped table-hover">
                <thead>
                    <tr>
                        <th>Code</th>
                        <th>Title</th>
                        <th>Department</th>
                        <th>Credits</th>
                        <th>Instructor</th>
                        <th>Schedule</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var course in filteredCourses)
                    {
                        <tr>
                            <td>@course.Code</td>
                            <td>@course.Title</td>
                            <td>@course.DepartmentName</td>
                            <td>@course.Credits</td>
                            <td>@course.Instructor.Name</td>
                            <td>@course.Schedule</td>
                            <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
        <p class="text-muted">Showing @filteredCourses.Count course(s)</p>
    }
    else
    {
        <div class="alert alert-info">No courses match your search criteria.</div>
    }
</div>

@code {
    private List<Department> departments = new();
    private List<Course> filteredCourses = new();

    private string? _searchTerm;
    private string? searchTerm
    {
        get => _searchTerm;
        set
        {
            _searchTerm = value;
            FilterCourses();
        }
    }

    private int _selectedDepartmentId;
    private int selectedDepartmentId
    {
        get => _selectedDepartmentId;
        set
        {
            _selectedDepartmentId = value;
            FilterCourses();
        }
    }

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        FilterCourses();
    }

    private void FilterCourses()
    {
        filteredCourses = CatalogService.SearchCourses(
            _searchTerm,
            _selectedDepartmentId > 0 ? _selectedDepartmentId : null);
    }
}

@page "/departments"
@inject ICatalogService CatalogService

<PageTitle>Departments - University Course Catalog</PageTitle>

<div class="container">
    <h1 class="mb-4">Departments</h1>

    <div class="row row-cols-1 row-cols-md-2 g-4">
        @foreach (var dept in departments)
        {
            <div class="col">
                <div class="card h-100">
                    <div class="card-body">
                        <h4 class="card-title">@dept.Name</h4>
                        <span class="badge bg-secondary mb-2">@dept.Code</span>
                        <p class="card-text">@dept.Description</p>
                    </div>
                    <div class="card-footer">
                        <a href="courses?departmentId=@dept.Id" class="btn btn-outline-primary">View Courses</a>
                    </div>
                </div>
            </div>
        }
    </div>
</div>

@code {
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
    }
}

@page "/enroll"
@inject ICatalogService CatalogService
@inject NavigationManager Navigation

<PageTitle>Enroll - University Course Catalog</PageTitle>

<div class="container">
    <h1 class="mb-4">Course Enrollment</h1>

    @if (submitted)
    {
        <div class="alert alert-success">
            <h4 class="alert-heading">Enrollment Request Submitted!</h4>
            <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for <strong>@GetCourseName(Model.CourseId)</strong> has been received.</p>
            <p>Your Student ID: <strong>@Model.StudentId</strong></p>
            <hr />
            <p class="mb-0">You will receive a confirmation email once your enrollment is processed.</p>
        </div>
        <a href="enroll" class="btn btn-primary">Submit Another Request</a>
        <a href="courses" class="btn btn-outline-secondary ms-2">Browse Courses</a>
    }
    else
    {
        <div class="row">
            <div class="col-lg-6">
                <EditForm Model="Model" FormName="enrollment" OnValidSubmit="HandleSubmit" method="post">
                    <DataAnnotationsValidator />
                    <ValidationSummary class="text-danger" />

                    <div class="mb-3">
                        <label for="studentName" class="form-label">Full Name</label>
                        <InputText id="studentName" class="form-control" @bind-Value="Model.StudentName" />
                        <ValidationMessage For="() => Model.StudentName" class="text-danger" />
                    </div>

                    <div class="mb-3">
                        <label for="studentId" class="form-label">Student ID</label>
                        <InputText id="studentId" class="form-control" @bind-Value="Model.StudentId" placeholder="e.g., CS123456" />
                        <ValidationMessage For="() => Model.StudentId" class="text-danger" />
                        <div class="form-text">Format: 2 uppercase letters followed by 6 digits</div>
                    </div>

                    <div class="mb-3">
                        <label for="courseId" class="form-label">Course</label>
                        <InputSelect id="courseId" class="form-select" @bind-Value="Model.CourseId">
                            <option value="0">-- Select a course --</option>
                            @foreach (var course in courses)
                            {
                                <option value="@course.Id">@course.Code - @course.Title</option>
                            }
                        </InputSelect>
                        <ValidationMessage For="() => Model.CourseId" class="text-danger" />
                    </div>

                    <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
                    <a href="courses" class="btn btn-outline-secondary ms-2">Cancel</a>
                </EditForm>
            </div>
        </div>
    }
</div>

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    private int? CourseId { get; set; }

    private List<Course> courses = new();
    private bool submitted;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetCourses();

        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        if (CatalogService.SubmitEnrollmentRequest(Model))
        {
            submitted = true;
        }
    }

    private string GetCourseName(int courseId)
    {
        var course = CatalogService.GetCourse(courseId);
        return course is not null ? $"{course.Code} - {course.Title}" : "Unknown Course";
    }
}

