+@page "/courses"
+@rendermode InteractiveServer
+@inject ICatalogService CatalogService
+
+<PageTitle>Course Catalog - University Course Catalog</PageTitle>
+
+<div class="container">
+    <h1 class="mb-4">Course Catalog</h1>
+
+    <div class="row mb-4">
+        <div class="col-md-6">
+            <input type="text" class="form-control" placeholder="Search by title, code, or instructor..."
+                   @bind="searchTerm" @bind:event="oninput" />
+        </div>
+        <div class="col-md-4">
+            <select class="form-select" @bind="selectedDepartmentId">
+                <option value="0">All Departments</option>
+                @foreach (var dept in departments)
+                {
+                    <option value="@dept.Id">@dept.Name</option>
+                }
+            </select>
+        </div>
+    </div>
+
+    @if (filteredCourses.Any())
+    {
+        <div class="table-responsive">
+            <table class="table table-striped table-hover">
+                <thead>
+                    <tr>
+                        <th>Code</th>
+                        <th>Title</th>
+                        <th>Department</th>
+                        <th>Credits</th>
+                        <th>Instructor</th>
+                        <th>Schedule</th>
+                        <th></th>
+                    </tr>
+                </thead>
+                <tbody>
+                    @foreach (var course in filteredCourses)
+                    {
+                        <tr>
+                            <td>@course.Code</td>
+                            <td>@course.Title</td>
+                            <td>@course.DepartmentName</td>
+                            <td>@course.Credits</td>
+                            <td>@course.Instructor.Name</td>
+                            <td>@course.Schedule</td>
+                            <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
+                        </tr>
+                    }
+                </tbody>
+            </table>
+        </div>
+        <p class="text-muted">Showing @filteredCourses.Count course(s)</p>
+    }
+    else
+    {
+        <div class="alert alert-info">No courses match your search criteria.</div>
+    }
+</div>
+
+@code {
+    private List<Department> departments = new();
+    private List<Course> filteredCourses = new();
+
+    private string? _searchTerm;
+    private string? searchTerm
+    {
+        get => _searchTerm;
+        set
+        {
+            _searchTerm = value;
+            FilterCourses();
+        }
+    }
+
+    private int _selectedDepartmentId;
+    private int selectedDepartmentId
+    {
+        get => _selectedDepartmentId;
+        set
+        {
+            _selectedDepartmentId = value;
+            FilterCourses();
+        }
+    }
+
+    protected override void OnInitialized()
+    {
+        departments = CatalogService.GetDepartments();
+        FilterCourses();
+    }
+
+    private void FilterCourses()
+    {
+        filteredCourses = CatalogService.SearchCourses(
+            _searchTerm,
+            _selectedDepartmentId > 0 ? _selectedDepartmentId : null);
+    }
+}
+

