 @page "/enroll"
 @inject ICatalogService CatalogService
 @inject NavigationManager Navigation

 <PageTitle>Enroll - University Course Catalog</PageTitle>

 <div class="container">
     <h1 class="mb-4">Course Enrollment</h1>

     @if (submitted)
     {
         <div class="alert alert-success">
             <h4 class="alert-heading">Enrollment Request Submitted!</h4>
             <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for <strong>@GetCourseName(Model.CourseId)</strong> has been received.</p>
             <p>Your Student ID: <strong>@Model.StudentId</strong></p>
             <hr />
             <p class="mb-0">You will receive a confirmation email once your enrollment is processed.</p>
         </div>
         <a href="enroll" class="btn btn-primary">Submit Another Request</a>
         <a href="courses" class="btn btn-outline-secondary ms-2">Browse Courses</a>
     }
     else
     {
         <div class="row">
             <div class="col-lg-6">
                 <EditForm Model="Model" FormName="enrollment" OnValidSubmit="HandleSubmit" method="post">
                     <DataAnnotationsValidator />
                     <ValidationSummary class="text-danger" />

                     <div class="mb-3">
                         <label for="studentName" class="form-label">Full Name</label>
                         <InputText id="studentName" class="form-control" @bind-Value="Model.StudentName" />
                         <ValidationMessage For="() => Model.StudentName" class="text-danger" />
                     </div>

                     <div class="mb-3">
                         <label for="studentId" class="form-label">Student ID</label>
                         <InputText id="studentId" class="form-control" @bind-Value="Model.StudentId" placeholder="e.g., CS123456" />
                         <ValidationMessage For="() => Model.StudentId" class="text-danger" />
                         <div class="form-text">Format: 2 uppercase letters followed by 6 digits</div>
                     </div>

                     <div class="mb-3">
                         <label for="courseId" class="form-label">Course</label>
                         <InputSelect id="courseId" class="form-select" @bind-Value="Model.CourseId">
                             <option value="0">-- Select a course --</option>
                             @foreach (var course in courses)
                             {
                                 <option value="@course.Id">@course.Code - @course.Title</option>
                             }
                         </InputSelect>
                         <ValidationMessage For="() => Model.CourseId" class="text-danger" />
                     </div>

                     <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
                     <a href="courses" class="btn btn-outline-secondary ms-2">Cancel</a>
                 </EditForm>
             </div>
         </div>
     }
 </div>

 @code {
     [SupplyParameterFromForm]
     private EnrollmentRequest Model { get; set; } = new();

     [SupplyParameterFromQuery]
     private int? CourseId { get; set; }

     private List<Course> courses = new();
     private bool submitted;

     protected override void OnInitialized()
     {
         courses = CatalogService.GetCourses();

         if (CourseId.HasValue && Model.CourseId == 0)
         {
             Model.CourseId = CourseId.Value;
         }
     }

     private void HandleSubmit()
     {
         if (CatalogService.SubmitEnrollmentRequest(Model))
         {
             submitted = true;
         }
     }

     private string GetCourseName(int courseId)
     {
         var course = CatalogService.GetCourse(courseId);
         return course is not null ? $"{course.Code} - {course.Title}" : "Unknown Course";
     }
 }

